import { RefProxy, ReadonlyRefProxy } from "@hoge1e3/ref";
export type PathRefProxy<T> = <N>(o: T) => ReadonlyPathRefProxy<N> & {
    [K in keyof T]: PathRefProxy<T[K]>;
} & RefProxy<T>;
export type ReadonlyPathRefProxy<T> = <N>(o: T) => ReadonlyPathRefProxy<N> & {
    [K in keyof T]: PathRefProxy<T[K]>;
} & ReadonlyRefProxy<T>;
export declare function create<T>(val: T): void;
